DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "scaffold.pl",
  "PCCmacros.pl",
  "parserMultiAnswer.pl",
  "contextCurrency.pl",
  "contextForm.pl",
  "parserLinearRelation.pl",
  "parserGraphTool.pl",
  "randomPerson.pl",
  "Pd.pl",
  "PGcourse.pl",
);
